import React from "react";

function Login() {
  return (
    <div className="login-box">
      <h2>Login</h2>

      <input placeholder="Username" />
      <input type="password" placeholder="Password" />

      <button>Login</button>

      <p>Don't have an account? Signup</p>
    </div>
  );
}

export default Login;
